import type { BridgeInterface, BridgeTask, BridgeResult, BridgeStreamEvent, MessagePart, TodoItem } from './types.js'
import { env } from '../env.js'

export class OpenCodeBridge implements BridgeInterface {
  name = 'opencode'
  private baseUrl: string
  private activeSessions = new Map<string, AbortController>()
  private available = false
  private lastAvailabilityCheck = 0

  constructor() {
    this.baseUrl = env.OPENCODE_URL
  }

  async initialize(): Promise<void> {
    await this.checkAvailability()
  }

  private async checkAvailability(): Promise<boolean> {
    try {
      const res = await fetch(`${this.baseUrl}/session`, {
        method: 'GET',
        signal: AbortSignal.timeout(3000),
      })
      this.available = res.ok
    } catch {
      this.available = false
    }
    this.lastAvailabilityCheck = Date.now()
    return this.available
  }

  isAvailable(): boolean {
    // Re-check every 30 seconds
    if (Date.now() - this.lastAvailabilityCheck > 30000) {
      this.checkAvailability()
    }
    return this.available
  }

  async executeTask(task: BridgeTask): Promise<BridgeResult> {
    return this.streamResponse(task, () => {})
  }

  async streamResponse(task: BridgeTask, onEvent: (event: BridgeStreamEvent) => void): Promise<BridgeResult> {
    const controller = new AbortController()
    this.activeSessions.set(task.sessionId, controller)

    try {
      // Re-check availability before each execution
      const reachable = await this.checkAvailability()
      if (!reachable) {
        return {
          success: false,
          output: '',
          error: `OpenCode server is not reachable at ${this.baseUrl}. Make sure OpenCode is running with: opencode serve`,
        }
      }

      onEvent({
        type: 'status',
        content: 'Connecting to OpenCode...',
        timestamp: new Date().toISOString(),
      })

      // Create or reuse OpenCode session
      const opencodeSessionId = await this.resolveOpenCodeSession(task)

      onEvent({
        type: 'status',
        content: 'Sending prompt to AI agent...',
        timestamp: new Date().toISOString(),
      })

      // Build the prompt with project context
      const contextPrompt = this.buildContextPrompt(task)

      // Send the chat message to OpenCode — this blocks until the agent finishes
      const chatResponse = await fetch(`${this.baseUrl}/session/${opencodeSessionId}/chat`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: contextPrompt }),
        signal: controller.signal,
      })

      if (!chatResponse.ok) {
        const errText = await chatResponse.text().catch(() => 'Unknown error')
        return {
          success: false,
          output: '',
          error: `OpenCode returned status ${chatResponse.status}: ${errText}`,
        }
      }

      onEvent({
        type: 'status',
        content: 'AI agent completed. Processing response...',
        timestamp: new Date().toISOString(),
      })

      // Fetch messages from the OpenCode session to get the full response
      const messagesRes = await fetch(`${this.baseUrl}/session/${opencodeSessionId}/message`, {
        method: 'GET',
        signal: AbortSignal.timeout(10000),
      })

      let textOutput = ''
      const parts: MessagePart[] = []

      if (messagesRes.ok) {
        const messages = await messagesRes.json() as OpenCodeMessage[]
        // Get the latest assistant message(s) since our prompt
        const assistantMessages = messages.filter((m) => m.role === 'assistant')
        const lastAssistant = assistantMessages[assistantMessages.length - 1]

        if (lastAssistant) {
          const parsed = this.parseOpenCodeMessage(lastAssistant)
          textOutput = parsed.text
          parts.push(...parsed.parts)

          // Emit events for each part
          for (const part of parsed.parts) {
            if (part.type === 'thinking') {
              onEvent({ type: 'thinking', content: part.content, timestamp: new Date().toISOString() })
            } else if (part.type === 'file') {
              onEvent({
                type: 'file-op',
                content: `${part.action}: ${part.path}`,
                timestamp: new Date().toISOString(),
                metadata: { action: part.action, path: part.path, newPath: part.newPath },
              })
            } else if (part.type === 'todo-list') {
              onEvent({
                type: 'todo',
                content: JSON.stringify(part.items),
                timestamp: new Date().toISOString(),
              })
            }
          }
        }
      }

      // If we didn't get text from messages, try to use the chat response body
      if (!textOutput) {
        try {
          const chatBody = await chatResponse.json() as Record<string, unknown>
          if (typeof chatBody === 'object' && chatBody !== null) {
            if (typeof chatBody.text === 'string') textOutput = chatBody.text
            else if (typeof chatBody.content === 'string') textOutput = chatBody.content
            else if (typeof chatBody.output === 'string') textOutput = chatBody.output
            else textOutput = JSON.stringify(chatBody)
          }
        } catch {
          // Chat response might have already been consumed or be non-JSON
          textOutput = 'Agent completed the task.'
        }
      }

      onEvent({ type: 'complete', content: 'Done', timestamp: new Date().toISOString() })

      return {
        success: true,
        output: textOutput,
        metadata: {
          opencodeSessionId,
          parts: parts.length > 0 ? parts : undefined,
        },
      }
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') {
        return { success: false, output: '', error: 'Execution cancelled' }
      }
      const msg = err instanceof Error ? err.message : 'Unknown error'
      return { success: false, output: '', error: `OpenCode bridge error: ${msg}` }
    } finally {
      this.activeSessions.delete(task.sessionId)
    }
  }

  async cancelExecution(sessionId: string): Promise<void> {
    const controller = this.activeSessions.get(sessionId)
    if (controller) {
      controller.abort()
      this.activeSessions.delete(sessionId)
    }
  }

  private async resolveOpenCodeSession(task: BridgeTask): Promise<string> {
    const existingId = task.context?.opencodeSessionId

    // Try to reuse existing OpenCode session
    if (existingId) {
      try {
        const res = await fetch(`${this.baseUrl}/session/${existingId}`, {
          method: 'GET',
          signal: AbortSignal.timeout(5000),
        })
        if (res.ok) return existingId
      } catch {
        // Session doesn't exist anymore, create a new one
      }
    }

    // Create a new OpenCode session
    const res = await fetch(`${this.baseUrl}/session`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({}),
      signal: AbortSignal.timeout(10000),
    })

    if (!res.ok) {
      throw new Error(`Failed to create OpenCode session: status ${res.status}`)
    }

    const session = await res.json() as { id: string }
    return session.id
  }

  private buildContextPrompt(task: BridgeTask): string {
    const ctx = task.context
    if (!ctx?.projectName) return task.prompt

    const lines: string[] = []
    lines.push(`[AuroraCraft Project Context]`)
    lines.push(`Project: ${ctx.projectName}`)
    if (ctx.software) lines.push(`Server Software: ${ctx.software}`)
    if (ctx.language) lines.push(`Language: ${ctx.language}`)
    if (ctx.compiler) lines.push(`Build Tool: ${ctx.compiler}`)
    if (ctx.javaVersion) lines.push(`Java Version: ${ctx.javaVersion}`)
    lines.push('')
    lines.push('RESTRICTIONS:')
    lines.push('- Do NOT execute build commands (mvn, gradle, javac, make)')
    lines.push('- Do NOT execute destructive or long-running terminal commands')
    lines.push('- You may only use terminal for file/folder finding and essential read operations')
    lines.push('- Focus on writing clean, well-structured Minecraft plugin code')
    lines.push('')
    lines.push(`User Request: ${task.prompt}`)

    return lines.join('\n')
  }

  private parseOpenCodeMessage(message: OpenCodeMessage): { text: string; parts: MessagePart[] } {
    const parts: MessagePart[] = []
    const textChunks: string[] = []

    // If message has parts array, parse each part
    if (Array.isArray(message.parts)) {
      for (const part of message.parts) {
        const partType = part.type ?? ''

        // Text content
        if (partType === 'text' || partType === 'text-delta' || partType === 'text-start') {
          const text = part.content ?? part.text ?? ''
          if (text) textChunks.push(text)
        }

        // Thinking / reasoning
        else if (partType === 'reasoning' || partType === 'reasoning-delta' || partType === 'thinking') {
          const content = part.content ?? part.text ?? ''
          if (content) parts.push({ type: 'thinking', content })
        }

        // Tool calls — file operations
        else if (partType === 'tool-call' || partType === 'tool_call' || partType === 'tool-invocation') {
          const toolName = (part.tool ?? part.name ?? part.toolName ?? '').toLowerCase()
          const args = part.args ?? part.arguments ?? part.input ?? {}

          if (toolName === 'write' || toolName === 'file_write' || toolName === 'create') {
            const filePath = args.path ?? args.file_path ?? args.filename ?? ''
            if (filePath) parts.push({ type: 'file', action: 'create', path: String(filePath) })
          } else if (toolName === 'edit' || toolName === 'file_edit' || toolName === 'str_replace' || toolName === 'patch') {
            const filePath = args.path ?? args.file_path ?? args.filename ?? ''
            if (filePath) parts.push({ type: 'file', action: 'update', path: String(filePath) })
          } else if (toolName === 'delete' || toolName === 'file_delete' || toolName === 'remove') {
            const filePath = args.path ?? args.file_path ?? args.filename ?? ''
            if (filePath) parts.push({ type: 'file', action: 'delete', path: String(filePath) })
          } else if (toolName === 'rename' || toolName === 'move' || toolName === 'file_rename') {
            const oldPath = args.path ?? args.old_path ?? args.source ?? ''
            const newPath = args.new_path ?? args.destination ?? args.target ?? ''
            if (oldPath) parts.push({ type: 'file', action: 'rename', path: String(oldPath), newPath: String(newPath) })
          }
          // Skip bash/shell commands — not shown in UI per requirements
        }

        // Todo items
        else if (partType === 'todo' || partType === 'todo-list' || partType === 'plan') {
          const items = this.parseTodoItems(part)
          if (items.length > 0) parts.push({ type: 'todo-list', items })
        }
      }
    }

    // If no parts found, use message content directly
    if (textChunks.length === 0) {
      const fallback = message.content ?? ''
      if (fallback) textChunks.push(fallback)
    }

    return { text: textChunks.join(''), parts }
  }

  private parseTodoItems(part: OpenCodePart): TodoItem[] {
    const items: TodoItem[] = []

    // Try 'items' array in the part
    const rawItems = part.items ?? part.todos ?? part.tasks ?? []
    if (Array.isArray(rawItems)) {
      for (const item of rawItems) {
        if (typeof item === 'string') {
          items.push({ text: item, status: 'pending' })
        } else if (typeof item === 'object' && item !== null) {
          const text = item.text ?? item.title ?? item.description ?? String(item)
          const status = item.status === 'completed' || item.done === true
            ? 'completed'
            : item.status === 'in-progress' || item.status === 'running'
              ? 'in-progress'
              : 'pending'
          items.push({ text: String(text), status })
        }
      }
    }

    // Try parsing content as a todo list (markdown checkbox format)
    const content = part.content ?? part.text ?? ''
    if (typeof content === 'string' && items.length === 0) {
      const lines = content.split('\n')
      for (const line of lines) {
        const checkMatch = line.match(/^[-*]\s*\[([ xX✓])\]\s*(.+)/)
        if (checkMatch) {
          const done = checkMatch[1] !== ' '
          items.push({ text: checkMatch[2].trim(), status: done ? 'completed' : 'pending' })
        }
      }
    }

    return items
  }
}

// Types for parsing OpenCode responses (flexible to handle various shapes)
interface OpenCodePart {
  type?: string
  content?: string
  text?: string
  tool?: string
  name?: string
  toolName?: string
  args?: Record<string, unknown>
  arguments?: Record<string, unknown>
  input?: Record<string, unknown>
  items?: Array<Record<string, unknown>>
  todos?: Array<Record<string, unknown>>
  tasks?: Array<Record<string, unknown>>
  done?: boolean
  status?: string
  [key: string]: unknown
}

interface OpenCodeMessage {
  id?: string
  sessionId?: string
  role?: string
  content?: string
  parts?: OpenCodePart[]
  [key: string]: unknown
}

import type { FastifyInstance } from 'fastify'
import { z } from 'zod'
import { eq, and, desc } from 'drizzle-orm'
import { db } from '../db/index.js'
import { projects } from '../db/schema/projects.js'
import { agentSessions } from '../db/schema/agent-sessions.js'
import { agentMessages } from '../db/schema/agent-messages.js'
import { agentLogs } from '../db/schema/agent-logs.js'
import { authMiddleware } from '../middleware/auth.js'
import { agentExecutor } from '../agents/executor.js'

const sendMessageSchema = z.object({
  content: z.string().min(1).max(10000),
})

async function verifyProjectOwnership(userId: string, projectId: string) {
  const [project] = await db
    .select()
    .from(projects)
    .where(and(eq(projects.id, projectId), eq(projects.userId, userId)))
    .limit(1)
  return project
}

export async function agentRoutes(app: FastifyInstance) {
  // List agent sessions for a project
  app.get('/api/projects/:projectId/agent/sessions', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId } = request.params as { projectId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const sessions = await db
      .select()
      .from(agentSessions)
      .where(eq(agentSessions.projectId, projectId))
      .orderBy(desc(agentSessions.createdAt))

    return sessions
  })

  // Create a new agent session
  app.post('/api/projects/:projectId/agent/sessions', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId } = request.params as { projectId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .insert(agentSessions)
      .values({ projectId })
      .returning()

    return reply.status(201).send(session)
  })

  // Get a specific agent session with its messages
  app.get('/api/projects/:projectId/agent/sessions/:sessionId', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    const messages = await db
      .select()
      .from(agentMessages)
      .where(eq(agentMessages.sessionId, sessionId))
      .orderBy(agentMessages.createdAt)

    return { ...session, messages }
  })

  // Send a message to an agent session
  app.post('/api/projects/:projectId/agent/sessions/:sessionId/messages', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }
    const parsed = sendMessageSchema.safeParse(request.body)
    if (!parsed.success) {
      return reply.status(400).send({
        message: parsed.error.issues[0].message,
        statusCode: 400,
      })
    }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    // Save the user message
    const [message] = await db
      .insert(agentMessages)
      .values({
        sessionId,
        role: 'user',
        content: parsed.data.content,
      })
      .returning()

    // Set session to running
    await db
      .update(agentSessions)
      .set({ status: 'running', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    // Fetch conversation history for context
    const history = await db
      .select({ role: agentMessages.role, content: agentMessages.content })
      .from(agentMessages)
      .where(eq(agentMessages.sessionId, sessionId))
      .orderBy(agentMessages.createdAt)

    // Fire-and-forget: launch the AI agent executor asynchronously
    agentExecutor.execute(
      {
        sessionId,
        projectId,
        prompt: parsed.data.content,
        bridgeName: 'opencode',
        opencodeSessionId: session.opencodeSessionId ?? undefined,
        projectName: project.name,
        software: project.software,
        language: project.language,
        compiler: project.compiler,
        javaVersion: project.javaVersion,
        conversationHistory: history.map((m) => ({ role: m.role, content: m.content })),
      },
      {
        onOutput: (content) => { app.log.debug({ sessionId }, `Agent output: ${content.substring(0, 100)}`) },
        onStatus: (status) => { app.log.info({ sessionId, status }, 'Agent status changed') },
        onLog: (logType, msg) => { app.log.debug({ sessionId, logType }, msg) },
        onComplete: () => { app.log.info({ sessionId }, 'Agent execution completed') },
        onError: (error) => { app.log.error({ sessionId, error }, 'Agent execution error') },
      },
    ).catch((err) => {
      app.log.error({ sessionId, err }, 'Unhandled agent execution error')
    })

    return reply.status(201).send(message)
  })

  // Cancel an agent session
  app.post('/api/projects/:projectId/agent/sessions/:sessionId/cancel', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    if (session.status !== 'running' && session.status !== 'idle') {
      return reply.status(400).send({ message: 'Session is not active', statusCode: 400 })
    }

    await agentExecutor.cancel(sessionId)

    const [updated] = await db
      .update(agentSessions)
      .set({ status: 'cancelled', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))
      .returning()

    await db.insert(agentLogs).values({
      sessionId,
      logType: 'status',
      message: 'Session cancelled by user',
    })

    return updated
  })

  // Get logs for a session
  app.get('/api/projects/:projectId/agent/sessions/:sessionId/logs', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const logs = await db
      .select()
      .from(agentLogs)
      .where(eq(agentLogs.sessionId, sessionId))
      .orderBy(agentLogs.createdAt)

    return logs
  })
}

import { eq } from 'drizzle-orm'
import { db } from '../db/index.js'
import { agentSessions } from '../db/schema/agent-sessions.js'
import { agentMessages } from '../db/schema/agent-messages.js'
import { agentLogs } from '../db/schema/agent-logs.js'
import { bridgeRegistry } from '../bridges/index.js'
import type { AgentExecutionContext, AgentStreamCallback, AgentExecutionResult } from './types.js'

export class AgentExecutor {
  private activeExecutions = new Map<string, boolean>()

  async execute(context: AgentExecutionContext, callbacks: AgentStreamCallback): Promise<AgentExecutionResult> {
    const bridge = bridgeRegistry.get(context.bridgeName) ?? bridgeRegistry.getDefault()
    if (!bridge) {
      const error = 'No AI bridge is configured'
      await this.failSession(context.sessionId, error)
      callbacks.onError(error)
      return { status: 'failed', output: '', error }
    }

    // Check availability with a fresh async check
    if (!bridge.isAvailable()) {
      const error = `OpenCode is not running. Start it with: opencode serve`
      await this.failSession(context.sessionId, error)
      callbacks.onError(error)
      return { status: 'failed', output: '', error }
    }

    this.activeExecutions.set(context.sessionId, true)

    await db
      .update(agentSessions)
      .set({ status: 'running', updatedAt: new Date() })
      .where(eq(agentSessions.id, context.sessionId))

    callbacks.onStatus('running')
    await this.addLog(context.sessionId, 'status', 'Execution started')

    try {
      const result = await bridge.streamResponse(
        {
          sessionId: context.sessionId,
          projectId: context.projectId,
          prompt: context.prompt,
          context: {
            opencodeSessionId: context.opencodeSessionId,
            projectName: context.projectName,
            software: context.software,
            language: context.language,
            compiler: context.compiler,
            javaVersion: context.javaVersion,
            conversationHistory: context.conversationHistory,
          },
        },
        (event) => {
          if (!this.activeExecutions.get(context.sessionId)) return

          switch (event.type) {
            case 'output':
              callbacks.onOutput(event.content)
              break
            case 'error':
              callbacks.onError(event.content)
              break
            case 'status':
            case 'thinking':
            case 'file-op':
            case 'todo':
            case 'complete':
              callbacks.onLog(event.type, event.content)
              break
          }
        },
      )

      if (!this.activeExecutions.get(context.sessionId)) {
        return { status: 'cancelled', output: '' }
      }

      if (!result.success) {
        const error = result.error ?? 'Bridge execution failed'
        await this.failSession(context.sessionId, error)

        // Save error as agent message so user sees it in chat
        await db.insert(agentMessages).values({
          sessionId: context.sessionId,
          role: 'agent',
          content: `⚠️ ${error}`,
        })

        callbacks.onError(error)
        this.activeExecutions.delete(context.sessionId)
        return { status: 'failed', output: '', error }
      }

      // Save the agent response with metadata
      await db.insert(agentMessages).values({
        sessionId: context.sessionId,
        role: 'agent',
        content: result.output,
        metadata: result.metadata?.parts ? { parts: result.metadata.parts } : undefined,
      })

      // Store the OpenCode session ID for future message reuse
      if (result.metadata?.opencodeSessionId) {
        await db
          .update(agentSessions)
          .set({
            status: 'completed',
            opencodeSessionId: result.metadata.opencodeSessionId,
            updatedAt: new Date(),
          })
          .where(eq(agentSessions.id, context.sessionId))
      } else {
        await db
          .update(agentSessions)
          .set({ status: 'completed', updatedAt: new Date() })
          .where(eq(agentSessions.id, context.sessionId))
      }

      await this.addLog(context.sessionId, 'status', 'Execution completed')

      const executionResult: AgentExecutionResult = {
        status: 'completed',
        output: result.output,
        metadata: result.metadata,
      }

      callbacks.onComplete(executionResult)
      this.activeExecutions.delete(context.sessionId)
      return executionResult
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown error'
      await this.failSession(context.sessionId, errorMessage)

      // Save error as agent message
      await db.insert(agentMessages).values({
        sessionId: context.sessionId,
        role: 'agent',
        content: `⚠️ Error: ${errorMessage}`,
      }).catch(() => {})

      callbacks.onError(errorMessage)
      this.activeExecutions.delete(context.sessionId)
      return { status: 'failed', output: '', error: errorMessage }
    }
  }

  async cancel(sessionId: string): Promise<void> {
    this.activeExecutions.delete(sessionId)

    const bridges = bridgeRegistry.getAll()
    for (const bridge of bridges) {
      await bridge.cancelExecution(sessionId)
    }

    await db
      .update(agentSessions)
      .set({ status: 'cancelled', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    await this.addLog(sessionId, 'status', 'Execution cancelled')
  }

  isRunning(sessionId: string): boolean {
    return this.activeExecutions.get(sessionId) === true
  }

  private async failSession(sessionId: string, error: string): Promise<void> {
    await db
      .update(agentSessions)
      .set({ status: 'failed', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    await this.addLog(sessionId, 'error', error)
  }

  private async addLog(sessionId: string, logType: string, message: string): Promise<void> {
    await db.insert(agentLogs).values({ sessionId, logType, message })
  }
}

export const agentExecutor = new AgentExecutor()

export interface BridgeTask {
  sessionId: string
  projectId: string
  prompt: string
  context?: {
    opencodeSessionId?: string
    projectName?: string
    software?: string
    language?: string
    compiler?: string
    javaVersion?: string
    conversationHistory?: Array<{ role: string; content: string }>
  }
}

export interface BridgeStreamEvent {
  type: 'output' | 'error' | 'status' | 'complete' | 'thinking' | 'file-op' | 'todo'
  content: string
  timestamp: string
  metadata?: Record<string, unknown>
}

export type MessagePart =
  | { type: 'thinking'; content: string }
  | { type: 'file'; action: 'create' | 'update' | 'delete' | 'rename'; path: string; newPath?: string }
  | { type: 'todo-list'; items: TodoItem[] }

export interface TodoItem {
  text: string
  status: 'pending' | 'in-progress' | 'completed'
}

export interface BridgeResult {
  success: boolean
  output: string
  files?: Array<{ path: string; content: string }>
  error?: string
  metadata?: {
    opencodeSessionId?: string
    parts?: MessagePart[]
  }
}

export interface BridgeInterface {
  name: string
  initialize(): Promise<void>
  executeTask(task: BridgeTask): Promise<BridgeResult>
  streamResponse(task: BridgeTask, onEvent: (event: BridgeStreamEvent) => void): Promise<BridgeResult>
  cancelExecution(sessionId: string): Promise<void>
  isAvailable(): boolean
}

import type { BridgeInterface } from './types.js'
import { OpenCodeBridge } from './opencode.js'

class BridgeRegistry {
  private bridges = new Map<string, BridgeInterface>()

  register(bridge: BridgeInterface) {
    this.bridges.set(bridge.name, bridge)
  }

  get(name: string): BridgeInterface | undefined {
    return this.bridges.get(name)
  }

  getDefault(): BridgeInterface | undefined {
    // Return the first available bridge, or first bridge overall
    const available = this.getAvailable()
    return available.length > 0 ? available[0] : this.bridges.values().next().value
  }

  getAvailable(): BridgeInterface[] {
    return Array.from(this.bridges.values()).filter((b) => b.isAvailable())
  }

  getAll(): BridgeInterface[] {
    return Array.from(this.bridges.values())
  }
}

export const bridgeRegistry = new BridgeRegistry()

// Register built-in bridges
